// =============================================================
// Notifications Context - إشعارات حقيقية من الـ API
// =============================================================

import { createContext, useContext, useState, useEffect, useCallback, ReactNode } from 'react'
import { useAuth } from './auth-context'

export interface AppNotification {
  id: string
  type: string
  title: string
  message: string
  icon?: string
  read: boolean
  createdAt: Date
}

interface NotificationsContextType {
  notifications: AppNotification[]
  unreadCount: number
  markRead: (id: string) => void
  markAllRead: () => void
  addNotification: (n: Omit<AppNotification, 'id' | 'createdAt' | 'read'>) => void
  refresh: () => void
}

const NotificationsContext = createContext<NotificationsContextType>({
  notifications: [],
  unreadCount: 0,
  markRead: () => {},
  markAllRead: () => {},
  addNotification: () => {},
  refresh: () => {},
})

export function NotificationsProvider({ children }: { children: ReactNode }) {
  const { token, isLoggedIn } = useAuth()
  const [notifications, setNotifications] = useState<AppNotification[]>([])

  const fetchNotifications = useCallback(async () => {
    if (!token || !isLoggedIn) return
    try {
      const res = await fetch('/api/notifications', {
        headers: { Authorization: `Bearer ${token}` },
      })
      if (!res.ok) return
      const data = await res.json()
      const items = (data.notifications || []).map((n: {
        id: string; type: string; title: string; message: string;
        icon?: string; is_read: boolean; created_at: string
      }) => ({
        id: n.id,
        type: n.type,
        title: n.title,
        message: n.message,
        icon: n.icon,
        read: n.is_read,
        createdAt: new Date(n.created_at),
      }))
      setNotifications(items)
    } catch { /* silent */ }
  }, [token, isLoggedIn])

  // جلب الإشعارات عند بداية الجلسة + كل 30 ثانية
  useEffect(() => {
    if (!isLoggedIn) {
      setNotifications([])
      return
    }
    fetchNotifications()
    const interval = setInterval(fetchNotifications, 30000)
    return () => clearInterval(interval)
  }, [isLoggedIn, fetchNotifications])

  async function markRead(id: string) {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n))
    if (!token) return
    try {
      await fetch(`/api/notifications/read/${id}`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
      })
    } catch { /* silent */ }
  }

  async function markAllRead() {
    setNotifications(prev => prev.map(n => ({ ...n, read: true })))
    if (!token) return
    try {
      await fetch('/api/notifications/read-all', {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
      })
    } catch { /* silent */ }
  }

  // إضافة إشعار محلي فوراً (optimistic)
  function addNotification(n: Omit<AppNotification, 'id' | 'createdAt' | 'read'>) {
    const newN: AppNotification = {
      ...n,
      id: `local_${Date.now()}`,
      read: false,
      createdAt: new Date(),
    }
    setNotifications(prev => [newN, ...prev])
  }

  const unreadCount = notifications.filter(n => !n.read).length

  return (
    <NotificationsContext.Provider value={{
      notifications,
      unreadCount,
      markRead,
      markAllRead,
      addNotification,
      refresh: fetchNotifications,
    }}>
      {children}
    </NotificationsContext.Provider>
  )
}

export const useNotifications = () => useContext(NotificationsContext)

