arguments.command:
# إنشاء notifications table + accept_order function + مسح البيانات
psql "$DATABASE_URL" << 'EOSQL'
-- 1. Create notifications table
CREATE TABLE IF NOT EXISTS notifications (
  id         UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id    UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  type       TEXT NOT NULL DEFAULT 'system',
  title      TEXT NOT NULL,
  message    TEXT NOT NULL,
  icon       TEXT,
  is_read    BOOLEAN NOT NULL DEFAULT FALSE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_notif_user ON notifications(user_id, created_at DESC);

-- 2. Disable RLS on notifications (service role handles security)
ALTER TABLE notifications DISABLE ROW LEVEL SECURITY;

-- 3. accept_order function (atomic with FOR UPDATE lock)
CREATE OR REPLACE FUNCTION accept_order(p_order_id UUID, p_courier_id UUID)
RETURNS JSON
LANGUAGE plpgsql
AS $$
DECLARE v_status TEXT;
BEGIN
  SELECT status INTO v_status FROM orders WHERE id = p_order_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN json_build_object('success', false, 'message', 'الأوردر مش موجود');
  END IF;
  IF v_status != 'PENDING' THEN
    RETURN json_build_object('success', false, 'message', 'الأوردر اتحجز من حد تاني');
  END IF;
  UPDATE orders
    SET courier_id=p_courier_id, status='ACCEPTED',
        accepted_at=NOW(), updated_at=NOW()
  WHERE id=p_order_id;
  RETURN json_build_object('success', true, 'message', 'تم قبول الأوردر');
END;
$$;

-- 4. Ensure orders.updated_at column exists and has default
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='orders' AND column_name='updated_at') THEN
    ALTER TABLE orders ADD COLUMN updated_at TIMESTAMPTZ DEFAULT NOW();
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='orders' AND column_name='num_shops') THEN
    ALTER TABLE orders ADD COLUMN num_shops INTEGER DEFAULT 0;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='orders' AND column_name='recipient_phone') THEN
    ALTER TABLE orders ADD COLUMN recipient_phone TEXT;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='orders' AND column_name='accepted_at') THEN
    ALTER TABLE orders ADD COLUMN accepted_at TIMESTAMPTZ;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='orders' AND column_name='completed_at') THEN
    ALTER TABLE orders ADD COLUMN completed_at TIMESTAMPTZ;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='orders' AND column_name='cancelled_at') THEN
    ALTER TABLE orders ADD COLUMN cancelled_at TIMESTAMPTZ;
  END IF;
END $$;

-- 5. مسح كل البيانات الاختبارية
DELETE FROM notifications;
DELETE FROM order_items;
DELETE FROM orders;
DELETE FROM couriers;
DELETE FROM security_alerts;
DELETE FROM users WHERE role != 'ADMIN';

-- 6. Verify
SELECT 'notifications table' AS object, COUNT(*) AS rows FROM notifications
UNION ALL SELECT 'orders', COUNT(*) FROM orders
UNION ALL SELECT 'couriers', COUNT(*) FROM couriers
UNION ALL SELECT 'users (admins only)', COUNT(*) FROM users;
EOSQL

